import { Monitor, AlertTriangle, MonitorOff } from "lucide-react";
import { useState, useEffect, useRef, useCallback } from "react";
import { useProctoring } from "./ProctoringContext";

const ScreenPanel = () => {
  const { pushEvent } = useProctoring();
  const videoRef = useRef<HTMLVideoElement>(null);
  const [sharing, setSharing] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [tabActive, setTabActive] = useState(true);
  const streamRef = useRef<MediaStream | null>(null);

  const startSharing = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getDisplayMedia({
        video: { frameRate: 5 },
        audio: false,
      });
      streamRef.current = stream;
      if (videoRef.current) {
        videoRef.current.srcObject = stream;
      }
      setSharing(true);
      setError(null);
      pushEvent("Screen sharing started", "success", "screen");

      // Detect when user stops sharing
      stream.getVideoTracks()[0].addEventListener("ended", () => {
        setSharing(false);
        streamRef.current = null;
        pushEvent("Screen sharing stopped", "danger", "screen");
      });
    } catch {
      setError("Screen sharing denied");
    }
  }, []);

  // Tab visibility detection
  useEffect(() => {
    const handler = () => {
      setTabActive(!document.hidden);
      if (document.hidden) {
        pushEvent("Tab switching detected", "danger", "screen");
      }
    };
    document.addEventListener("visibilitychange", handler);
    return () => document.removeEventListener("visibilitychange", handler);
  }, []);

  // Cleanup on unmount
  useEffect(() => {
    return () => {
      streamRef.current?.getTracks().forEach((t) => t.stop());
    };
  }, []);

  return (
    <div className="glass neon-border p-4">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <Monitor className="w-4 h-4 text-primary" />
          <span className="text-sm font-semibold">Screen Monitor</span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className={`w-2 h-2 rounded-full ${sharing ? "bg-success animate-pulse" : "bg-danger"}`} />
          <span className={`text-xs ${sharing ? "text-success" : "text-danger"}`}>
            {sharing ? "Sharing" : "Not sharing"}
          </span>
        </div>
      </div>

      <div className="relative bg-muted/30 rounded-lg aspect-video overflow-hidden flex items-center justify-center">
        {!sharing && (
          <div className="absolute inset-0 z-10 flex flex-col items-center justify-center gap-3">
            <MonitorOff className="w-8 h-8 text-muted-foreground/50" />
            <button
              onClick={startSharing}
              className="px-4 py-2 rounded-lg bg-primary text-primary-foreground text-xs font-medium hover:bg-primary/80 transition-all neon-glow"
            >
              Start Screen Sharing
            </button>
            {error && (
              <span className="text-xs text-danger">{error}</span>
            )}
          </div>
        )}

        <video
          ref={videoRef}
          autoPlay
          muted
          playsInline
          className={`w-full h-full object-contain ${sharing ? "" : "hidden"}`}
        />

        {sharing && (
          <div className={`absolute top-2 right-2 text-[10px] px-2 py-0.5 rounded ${
            tabActive ? "bg-success/20 text-success" : "bg-danger/20 text-danger"
          }`}>
            {tabActive ? "Tab Active" : "Tab Hidden ΓÜá"}
          </div>
        )}

        {sharing && !tabActive && (
          <div className="absolute bottom-2 inset-x-2 bg-destructive/90 backdrop-blur-sm rounded-md px-3 py-2 flex items-center gap-2">
            <AlertTriangle className="w-4 h-4 text-destructive-foreground" />
            <span className="text-xs text-destructive-foreground font-medium">ΓÜá Tab switching detected</span>
          </div>
        )}
      </div>
    </div>
  );
};

export default ScreenPanel;

import { Mic, MicOff } from "lucide-react";
import { useState, useEffect, useRef, useCallback } from "react";
import { useProctoring } from "./ProctoringContext";

const VoicePanel = () => {
  const { pushEvent } = useProctoring();
  const [bars, setBars] = useState<number[]>(Array(40).fill(4));
  const [voiceDetected, setVoiceDetected] = useState(false);
  const [noiseLevel, setNoiseLevel] = useState<"low" | "moderate" | "high">("low");
  const [micActive, setMicActive] = useState(false);
  const [micError, setMicError] = useState<string | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const streamRef = useRef<MediaStream | null>(null);
  const rafRef = useRef<number>();

  const startMic = useCallback(async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;
      const ctx = new AudioContext();
      const source = ctx.createMediaStreamSource(stream);
      const analyser = ctx.createAnalyser();
      analyser.fftSize = 128;
      analyser.smoothingTimeConstant = 0.75;
      source.connect(analyser);
      analyserRef.current = analyser;
      setMicActive(true);
    } catch {
      setMicError("Microphone access denied");
    }
  }, []);

  useEffect(() => {
    startMic();
    return () => {
      streamRef.current?.getTracks().forEach((t) => t.stop());
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [startMic]);

  // Visualization loop
  useEffect(() => {
    if (!micActive || !analyserRef.current) return;

    const analyser = analyserRef.current;
    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    const draw = () => {
      analyser.getByteFrequencyData(dataArray);

      // Map frequency data to bar heights
      const barCount = 40;
      const step = Math.floor(bufferLength / barCount);
      const newBars: number[] = [];
      for (let i = 0; i < barCount; i++) {
        const val = dataArray[i * step] || 0;
        newBars.push(Math.max(3, (val / 255) * 56));
      }
      setBars(newBars);

      // Voice detection: average amplitude
      const avg = dataArray.reduce((a, b) => a + b, 0) / bufferLength;
      const detected = avg > 25;
      setVoiceDetected(detected);
      const level = avg < 10 ? "low" : avg < 40 ? "moderate" : "high";
      setNoiseLevel(level);

      if (level === "high") {
        pushEvent("High background noise detected", "warning", "voice");
      } else if (detected) {
        pushEvent("Voice activity detected", "info", "voice");
      }

      rafRef.current = requestAnimationFrame(draw);
    };

    rafRef.current = requestAnimationFrame(draw);
    return () => {
      if (rafRef.current) cancelAnimationFrame(rafRef.current);
    };
  }, [micActive]);

  return (
    <div className="glass neon-border p-4">
      <div className="flex items-center justify-between mb-3">
        <div className="flex items-center gap-2">
          <Mic className="w-4 h-4 text-primary" />
          <span className="text-sm font-semibold">Voice Activity</span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className={`w-2 h-2 rounded-full ${micActive ? "bg-success animate-pulse" : "bg-danger"}`} />
          <span className={`text-xs ${micActive ? "text-success" : "text-danger"}`}>
            {micActive ? "Active" : micError || "Loading..."}
          </span>
        </div>
      </div>

      {/* Waveform */}
      <div className="flex items-end justify-center gap-[2px] h-14 mb-4">
        {bars.map((h, i) => (
          <div
            key={i}
            className="w-[3px] rounded-full bg-gradient-to-t from-primary/40 to-primary transition-[height] duration-75"
            style={{ height: `${h}px` }}
          />
        ))}
      </div>

      <div className="flex items-center gap-4 text-xs">
        <div className="flex items-center gap-1.5">
          <div className={`w-2 h-2 rounded-full ${voiceDetected ? "bg-success animate-pulse" : "bg-muted-foreground/30"}`} />
          <span className="text-muted-foreground">
            {voiceDetected ? "Voice Detected" : "Silent"}
          </span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className={`w-2 h-2 rounded-full ${
            noiseLevel === "low" ? "bg-success" : noiseLevel === "moderate" ? "bg-warning" : "bg-danger"
          }`} />
          <span className="text-muted-foreground">
            {noiseLevel === "low" ? "Low Noise" : noiseLevel === "moderate" ? "Moderate Noise" : "High Noise"}
          </span>
        </div>
        <div className="flex items-center gap-1.5">
          <div className="w-2 h-2 rounded-full bg-success" />
          <span className="text-muted-foreground">Single Voice</span>
        </div>
      </div>
    </div>
  );
};

export default VoicePanel;

import { createClient } from '@supabase/supabase-js';
import type { Database } from './leaderboard-types';

const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;

export const supabase = createClient<Database>(supabaseUrl, supabaseAnonKey);

export async function updateUserXP(userId: string, xpToAdd: number) {
    const { data: user, error: fetchError } = await supabase
        .from('leaderboard_users')
        .select('xp, weekly_xp')
        .eq('id', userId)
        .single();

    if (fetchError && (fetchError as any).code !== 'PGRST116') throw fetchError;

    if (user) {
        const { error: updateError } = await supabase
            .from('leaderboard_users')
            .update({
                xp: (user.xp || 0) + xpToAdd,
                weekly_xp: (user.weekly_xp || 0) + xpToAdd,
            })
            .eq('id', userId);
        if (updateError) throw updateError;
    }
}

export async function syncUserProfile(profile: { id: string; username: string; avatar_url?: string }) {
    const { error } = await supabase
        .from('leaderboard_users')
        .upsert({
            id: profile.id,
            username: profile.username,
            avatar_url: profile.avatar_url || `https://api.dicebear.com/7.x/avataaars/svg?seed=${profile.username}`,
            xp: 0,
            level: 1,
            weekly_xp: 0,
            rank: 999,
        }, { onConflict: 'id' });

    if (error) throw error;
}

