import { useState, useEffect, useRef } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ArrowLeft, Mic, MicOff, Star, ChevronRight, Trophy } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { speakingPrompts } from "@/data/speakingPrompts";
import { getUser } from "@/lib/auth";
import { updateUserXP } from "@/lib/leaderboard-supabase";
import { callLanguageTool } from "@/lib/languageTool";
import { toast } from "sonner";

// Type definitions for Web Speech API
interface SpeechRecognitionEvent extends Event {
    results: {
        [index: number]: {
            [index: number]: {
                transcript: string;
            };
            isFinal: boolean;
        };
    };
}

interface SpeechRecognition extends EventTarget {
    continuous: boolean;
    interimResults: boolean;
    lang: string;
    start(): void;
    stop(): void;
    onresult: (event: SpeechRecognitionEvent) => void;
    onerror: (event: any) => void;
    onend: () => void;
}

declare global {
    interface Window {
        SpeechRecognition: any;
        webkitSpeechRecognition: any;
    }
}

const PREP_TIME = 10;   // 10 seconds prep
const SPEAK_TIME = 60;  // max 60 seconds speaking

const SpeakingModule = () => {
    const navigate = useNavigate();

    const [currentIndex, setCurrentIndex] = useState(() => {
        const saved = localStorage.getItem("speaking_current_index");
        return saved ? parseInt(saved) : 0;
    });
    const [phase, setPhase] = useState<"idle" | "prep" | "recording" | "done">("idle");
    const [prepLeft, setPrepLeft] = useState(PREP_TIME);
    const [elapsed, setElapsed] = useState(0);
    const [isFinished, setIsFinished] = useState(false);
    const [feedback, setFeedback] = useState<{
        overall: number; pronunciation: number; fluency: number; coherence: number; tips: string[];
    } | null>(null);
    const [transcript, setTranscript] = useState("");
    const [isEvaluating, setIsEvaluating] = useState(false);

    const recognitionRef = useRef<SpeechRecognition | null>(null);

    const timerRef = useRef<NodeJS.Timeout | null>(null);
    const currentPrompt = speakingPrompts[currentIndex];
    const totalPrompts = speakingPrompts.length;

    // Persist progress
    useEffect(() => {
        localStorage.setItem("speaking_current_index", currentIndex.toString());
        localStorage.setItem("speaking_progress_count", currentIndex.toString());
    }, [currentIndex]);

    const clearTimer = () => {
        if (timerRef.current) clearInterval(timerRef.current);
    };

    const startPrep = () => {
        setPhase("prep");
        setPrepLeft(PREP_TIME);
        timerRef.current = setInterval(() => {
            setPrepLeft(t => {
                if (t <= 1) {
                    clearInterval(timerRef.current!);
                    startRecording();
                    return 0;
                }
                return t - 1;
            });
        }, 1000);
    };

    const startRecording = () => {
        setPhase("recording");
        setElapsed(0);
        setTranscript("");

        // Setup Speech Recognition
        const SpeechRecognition = window.SpeechRecognition || window.webkitSpeechRecognition;
        if (SpeechRecognition) {
            const recognition = new SpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            recognition.lang = 'en-US';

            recognition.onresult = (event: SpeechRecognitionEvent) => {
                let currentTranscript = "";
                for (let i = 0; i < event.results.length; i++) {
                    currentTranscript += event.results[i][0].transcript;
                }
                setTranscript(currentTranscript);
            };

            recognition.onerror = (err: any) => {
                console.error("Speech Recognition Error:", err);
                toast.error("Microphone access or speech recognition error.");
            };

            recognition.start();
            recognitionRef.current = recognition;
        } else {
            toast.error("Speech Recognition is not supported in this browser.");
        }

        timerRef.current = setInterval(() => {
            setElapsed(e => {
                if (e >= SPEAK_TIME - 1) {
                    clearInterval(timerRef.current!);
                    stopRecording();
                    return SPEAK_TIME;
                }
                return e + 1;
            });
        }, 1000);
    };

    const stopRecording = async () => {
        clearTimer();
        if (recognitionRef.current) {
            recognitionRef.current.stop();
        }
        setPhase("done");
        setIsEvaluating(true);

        try {
            const aiResponse = await callLanguageTool({
                tool: "evaluate",
                text: JSON.stringify({
                    type: "speaking",
                    prompt: currentPrompt.prompt,
                    transcript: transcript || "No speech detected."
                })
            });

            const parsedFeedback = JSON.parse(aiResponse);
            setFeedback(parsedFeedback);

            const user = getUser();
            if (user?.id) {
                updateUserXP(user.id, Math.round(parsedFeedback.overall * 0.3)).catch(console.error);
            }
        } catch (error) {
            console.error("AI Evaluation Error:", error);
            // Fallback
            const overall = Math.floor(Math.random() * 20 + 70);
            setFeedback({
                overall,
                pronunciation: Math.min(100, overall + Math.floor(Math.random() * 10 - 5)),
                fluency: Math.min(100, overall + Math.floor(Math.random() * 10 - 5)),
