                            <div className="rounded-2xl p-6 mb-6" style={{ background: "hsla(270, 20%, 8%, 0.8)", border: "1px solid hsla(270, 60%, 55%, 0.15)", boxShadow: "0 0 30px hsla(270, 80%, 55%, 0.06)" }}>
                                <div className="flex items-center gap-3 mb-3">
